body:
I ended up using this patch if anyone else is waiting for the fix (your version may adjust slightly depending on the compiled output of the framework version in your node_modules):

```diff
diff --git a/dist/build/swc/index.js b/dist/build/swc/index.js
index 69ee65472ce835db30e4e4aaef49a8eb8b42395b..f259933a89dcb053da5131f904bcd1ec8a0959e9 100644
--- a/dist/build/swc/index.js
+++ b/dist/build/swc/index.js
@@ -499,41 +499,74 @@ function bindingToApi(binding, bindingPath, _wasm) {
                 else buffer[0] = item;
             }
         }
-        async function* createIterator() {
-            const task = await nativeFunction(emitResult);
-            try {
-                while(!canceled){
-                    if (buffer.length > 0) {
-                        const item = buffer.shift();
-                        if (item.err) throw item.err;
-                        yield item.value;
-                    } else {
-                        // eslint-disable-next-line no-loop-func
-                        yield new Promise((resolve, reject)=>{
-                            waiting = {
-                                resolve,
-                                reject
-                            };
-                        });
-                    }
+        // Manual async iterator — backport of vercel/next.js#91704 to work
+        // around a `RangeError: Map maximum size exceeded` crash in dev with
+        // Turbopack + React 19. The async generator this replaces registered
+        // 3–4 AsyncHook IDs per HMR event (generator object, step-Promise,
+        // yielded inner-Promise, for-await unwrapper); under heavy HMR
+        // subscription fan-out, the tracker's pendingOperations Map filled
+        // faster than GC could drain. This implementation returns one
+        // Promise<IteratorResult<T>> directly from next(), keeping async
+        // pressure proportional to active subscriptions rather than total
+        // events. Remove this patch once #91704 lands upstream.
+        let task;
+        nativeFunction(emitResult).then((t)=>{
+            if (canceled) {
+                if (t) binding.rootTaskDispose(t);
+            } else {
+                task = t;
+            }
+        }, (err)=>{
+            emitResult(err, undefined);
+        });
+        const iterator = {
+            [Symbol.asyncIterator] () {
+                return this;
+            },
+            next () {
+                if (canceled) {
+                    return Promise.resolve({
+                        value: undefined,
+                        done: true
+                    });
                 }
-            } catch (e) {
-                if (e === cancel) return;
-                throw e;
-            } finally{
-                if (task) {
-                    binding.rootTaskDispose(task);
+                if (buffer.length > 0) {
+                    const item = buffer.shift();
+                    if (item.err) return Promise.reject(item.err);
+                    return Promise.resolve({
+                        value: item.value,
+                        done: false
+                    });
                 }
+                // eslint-disable-next-line no-loop-func
+                return new Promise((resolve, reject)=>{
+                    waiting = {
+                        resolve: (value)=>resolve({
+                                value,
+                                done: false
+                            }),
+                        reject: (e)=>{
+                            if (e === cancel) {
+                                resolve({
+                                    value: undefined,
+                                    done: true
+                                });
+                            } else {
+                                reject(e);
+                            }
+                        }
+                    };
+                });
+            },
+            return: async ()=>{
+                canceled = true;
+                if (waiting) waiting.reject(cancel);
+                if (task) binding.rootTaskDispose(task);
+                return {
+                    value: undefined,
+                    done: true
+                };
             }
-        }
-        const iterator = createIterator();
-        iterator.return = async ()=>{
-            canceled = true;
-            if (waiting) waiting.reject(cancel);
-            return {
-                value: undefined,
-                done: true
-            };
         };
         return iterator;
     }
```

@bgw When you have some time, could you take a look at this?
It's a small change, but I feel like it makes sense to include it.
I remember you reviewed the `webpack.config.ts` file recently, so I thought I'd mention you.
